import java.util.HashMap;

public boolean canEqualFrequency(String word) {
    HashMap<Character, Integer> freq = new HashMap<>();
    for (char c : word.toCharArray()) {
        freq.put(c, freq.getOrDefault(c, 0) + 1);
    }

    HashMap<Integer, Integer> count_freq = new HashMap<>();
    for (int f : freq.values()) {
        count_freq.put(f, count_freq.getOrDefault(f, 0) + 1);
    }

    if (count_freq.size() != 2) {
        return false;
    }

    int a = (int) count_freq.keySet().toArray()[0];
    int acount = count_freq.get(a);
    int b = (int) count_freq.keySet().toArray()[1];
    int bcount = count_freq.get(b);

    return (acount == 1 && (a - 1 == b || a == 1)) || (bcount == 1 && (b - 1 == a || b == 1));
}
